export class LiveStreamsService {
    /**
     * Subscribe Stream
     * Subscribe to a presence stream via SSE (native async-generator).
     *
     * Events are pushed by ``ctx.send()`` from background tasks or by
     * ``StreamWriter`` from route handlers. ``_PING_INTERVAL = 3.0`` keeps the
     * connection alive through proxies. Closes after 30 minutes — client
     * reconnects with ``Last-Event-ID``.
     *
     * No-transform / no-buffering response headers are injected globally by
     * ``SseNoTransformMiddleware`` in ``main.py`` for any ``text/event-stream``
     * response — gzip in proxies (Next.js dev rewrites, nginx) batches small
     * SSE frames into bulk delivery and defeats streaming.
     * @param data The data for the request.
     * @param data.topic
     * @param data.resourceId
     * @param data.infospaceId
     * @param data.packageToken
     * @param data.params JSON-encoded view parameters
     * @param data.lastEventId
     * @param data.xPackageToken
     * @returns unknown Successful Response
     * @throws ApiError
     */
    public static subscribeStream(data: SubscribeStreamData): CancelablePromise<SubscribeStreamResponse> {
        return __request(OpenAPI, {
            method: 'GET',
            url: '/api/v1/infospaces/{infospace_id}/stream/{topic}/{resource_id}',
            path: {
                topic: data.topic,
                resource_id: data.resourceId,
                infospace_id: data.infospaceId
            },
            headers: {
                'Last-Event-ID': data.lastEventId,
                'X-Package-Token': data.xPackageToken
            },
            query: {
                package_token: data.packageToken,
                params: data.params
            },
            errors: {
                422: 'Validation Error'
            }
        });
    }
    
}

